/**
 * Form component for Template.
 * Auto-generated by scaffold utility.
 */

export function createTemplateForm({ item, onSubmit } = {}) {
  const form = document.createElement('form');
  form.className = 'template-form';

    const nameLabel = document.createElement('label');
    nameLabel.textContent = 'Name';
    nameLabel.setAttribute('for', 'name');
    const nameInput = document.createElement('input');
    nameInput.type = 'text';
    nameInput.name = 'name';
    nameInput.id = 'name';
    nameInput.required = true;
    if (item && item.name) nameInput.value = item.name;
    const nameGroup = document.createElement('div');
    nameGroup.className = 'form-group';
    nameGroup.append(nameLabel, nameInput);

    const categoryLabel = document.createElement('label');
    categoryLabel.textContent = 'Category';
    categoryLabel.setAttribute('for', 'category');
    const categorySelect = document.createElement('select');
    categorySelect.name = 'category';
    categorySelect.id = 'category';
      const categoryOptRiskfactors = document.createElement('option');
      categoryOptRiskfactors.value = 'risk-factors';
      categoryOptRiskfactors.textContent = 'risk-factors';
      categorySelect.append(categoryOptRiskfactors);
      const categoryOptManagementdiscussion = document.createElement('option');
      categoryOptManagementdiscussion.value = 'management-discussion';
      categoryOptManagementdiscussion.textContent = 'management-discussion';
      categorySelect.append(categoryOptManagementdiscussion);
      const categoryOptFinancialsummary = document.createElement('option');
      categoryOptFinancialsummary.value = 'financial-summary';
      categoryOptFinancialsummary.textContent = 'financial-summary';
      categorySelect.append(categoryOptFinancialsummary);
      const categoryOptLegaldisclaimers = document.createElement('option');
      categoryOptLegaldisclaimers.value = 'legal-disclaimers';
      categoryOptLegaldisclaimers.textContent = 'legal-disclaimers';
      categorySelect.append(categoryOptLegaldisclaimers);
      const categoryOptOther = document.createElement('option');
      categoryOptOther.value = 'other';
      categoryOptOther.textContent = 'other';
      categorySelect.append(categoryOptOther);
    if (item && item.category) categorySelect.value = item.category; else categorySelect.value = 'other';
    const categoryGroup = document.createElement('div');
    categoryGroup.className = 'form-group';
    categoryGroup.append(categoryLabel, categorySelect);

    const contentLabel = document.createElement('label');
    contentLabel.textContent = 'Content';
    contentLabel.setAttribute('for', 'content');
    const contentInput = document.createElement('textarea');
    contentInput.name = 'content';
    contentInput.id = 'content';
    contentInput.required = true;
    contentInput.rows = 12;
    contentInput.placeholder = 'Write your section content in Markdown...';
    if (item && item.content) contentInput.value = item.content;
    const contentGroup = document.createElement('div');
    contentGroup.className = 'form-group';
    contentGroup.append(contentLabel, contentInput);

    const submitButton = document.createElement('button');
    submitButton.type = 'submit';
    submitButton.className = 'btn btn--primary';
    submitButton.textContent = item ? 'Update' : 'Create';

    form.append(nameGroup, categoryGroup, contentGroup, submitButton);

    form.addEventListener('submit', (event) => {
      event.preventDefault();
      const data = {
      name: form.querySelector('[name="name"]').value,
      category: form.querySelector('[name="category"]').value,
      content: form.querySelector('[name="content"]').value,
      };
    if (!data.name || !data.name.trim()) { alert('Name is required.'); return; }
    if (!data.content || !data.content.trim()) { alert('Content is required.'); return; }
      if (onSubmit) onSubmit(data);
    });

    return form;
}
